//! Per-arch board/platform 配置（§六.D，参 StarryX xcore/src/config/<arch>.rs）。
//!
//! 这里只放**板级常量**（内存布局、设备物理地址、时钟频率），不放逻辑。
//! 高层一律 `crate::board::X` 取用；新增架构 = 加一个 `qemu_<arch>.rs` + 一行 cfg。
//! 这是与 `arch/mod.rs` 同级的 cfg 分发点，不算高层 `#[cfg(target_arch)]` 违例。

#[cfg(target_arch = "riscv64")]
#[path = "qemu_riscv64.rs"]
mod qemu;

#[cfg(target_arch = "loongarch64")]
#[path = "qemu_loongarch64.rs"]
mod qemu;

pub use qemu::*;

use std::env;
use std::fs::{self, File};
use std::io::Write;
use std::path::{Path, PathBuf};

fn collect_apps(app_dir: &Path) -> Vec<String> {
    if !app_dir.exists() {
        return Vec::new();
    }
    let mut apps = fs::read_dir(app_dir)
        .expect("failed to read user apps directory")
        .filter_map(|entry| {
            let entry = entry.ok()?;
            let path = entry.path();
            (path.extension().and_then(|ext| ext.to_str()) == Some("rs"))
                .then(|| path.file_stem().unwrap().to_string_lossy().to_string())
        })
        .collect::<Vec<_>>();
    apps.sort();
    apps
}

fn main() {
    let kernel_arch = env::var("CARGO_CFG_TARGET_ARCH").unwrap_or_else(|_| "riscv64".to_string());
    let user_target = match kernel_arch.as_str() {
        "loongarch64" => "loongarch64-unknown-none-softfloat",
        _ => "riscv64gc-unknown-none-elf",
    };
    let target_path = format!("../user/target/{}/release/", user_target);

    println!("cargo:rerun-if-changed=../user/src/");
    println!("cargo:rerun-if-changed={}", target_path);

    let out_dir = PathBuf::from(env::var("OUT_DIR").expect("OUT_DIR not set"));
    let app_dir = Path::new("../user/src/bin");
    let apps = if kernel_arch == "loongarch64" {
        vec!["initproc".to_string()]
    } else {
        collect_apps(app_dir)
    };
    for app in &apps {
        println!("cargo:rerun-if-changed={}{}", target_path, app);
    }
    let link_app_path = out_dir.join("link_app.S");
    let mut f = File::create(&link_app_path).expect("failed to create link_app.S");

    writeln!(f, ".align 3").unwrap();
    writeln!(f, ".section .data").unwrap();
    writeln!(f, ".global _num_app").unwrap();
    writeln!(f, "_num_app:").unwrap();
    writeln!(f, "    .quad {}", apps.len()).unwrap();
    for i in 0..apps.len() {
        writeln!(f, "    .quad app_{}_start", i).unwrap();
    }
    if apps.is_empty() {
        writeln!(f, "    .quad _num_app").unwrap();
    } else {
        writeln!(f, "    .quad app_{}_end", apps.len() - 1).unwrap();
    }

    for (idx, app) in apps.iter().enumerate() {
        let app_path = format!("{}{}", target_path, app);
        writeln!(f, ".section .data").unwrap();
        writeln!(f, ".align 3").unwrap();
        writeln!(f, ".global app_{}_start", idx).unwrap();
        writeln!(f, ".global app_{}_end", idx).unwrap();
        writeln!(f, "app_{}_start:", idx).unwrap();
        writeln!(f, "    .incbin \"{}\"", app_path).unwrap();
        writeln!(f, "app_{}_end:", idx).unwrap();
    }

    // Generate app_names.rs with the list of app names
    let app_names_path = out_dir.join("app_names.rs");
    let mut names_f = File::create(&app_names_path).expect("failed to create app_names.rs");
    writeln!(names_f, "pub const APP_NAMES: [&str; {}] = [", apps.len()).unwrap();
    for app in &apps {
        writeln!(names_f, "    \"{}\",", app).unwrap();
    }
    writeln!(names_f, "];").unwrap();

    // LOG 等级由编译期 option_env!("LOG") 读取（见 src/logging.rs）。
    // 声明依赖，确保切换 LOG= 时触发重新编译，否则 cargo 复用旧二进制。
    println!("cargo:rerun-if-env-changed=LOG");
    println!("cargo:rerun-if-env-changed=OSCOMP_DISK");

    // Generate smp_config.rs — compile-time SMP core count from Makefile
    println!("cargo:rerun-if-env-changed=STELLAR_SMP");
    let smp = env::var("STELLAR_SMP").unwrap_or_else(|_| "1".to_string());
    let smp_path = out_dir.join("smp_config.rs");
    let mut smp_f = File::create(&smp_path).expect("failed to create smp_config.rs");
    writeln!(
        smp_f,
        "/// 编译时 SMP 核数配置（来自 Makefile SMP={}）",
        smp
    )
    .unwrap();
    writeln!(smp_f, "pub const SMP_COUNT: usize = {};", smp).unwrap();
}

//! 架构抽象层 / 硬件抽象层（HAL）。
//!
//! 高层代码只依赖 `crate::arch::*`，各架构在子模块（`riscv64/`、`loongarch64/`…）各自实现，
//! 由本文件按 `target_arch` 统一重导出。验收：高层文件**零** `#[cfg(target_arch)]` 与
//! `riscv::`/`sbi_rt::` 直接引用（M0 已达成）。
//!
//! # arch 接口契约（HAL boundary）
//!
//! 本文件用**显式 `pub use`（非 glob `*`）固化接口**：每个架构子模块**必须**导出下列全部
//! 符号，否则切到该架构时**编译失败**——以此强制 LoongArch（及将来 x86/arm）与 riscv 接口
//! 对齐，避免"起 LA 后才发现少接口"。新增架构 = 建 `arch/<arch>/`，实现下表全部符号，
//! 在下方加一段 `#[cfg] pub use <arch>::{ 同一组 }` 即可，高层零改动。
//!
//! | 组 | 符号 | 语义 |
//! |----|------|------|
//! | 控制台 | `console_putchar(usize)` / `console_getchar()->usize` | 串口/SBI 收发字符（无字符返回 `usize::MAX`） |
//! | 定时器 | `set_timer(deadline:usize)` / `get_time()->usize` / `clock_freq()->usize` | 设下次定时中断 / 读硬件单调计数 / 计数频率 |
//! | 关机   | `shutdown(failure:bool)->!` | 主动关机（评测要求） |
//! | SMP/CPU| `send_ipi(...)->ArchRet` / `hart_id()->usize` | 跨核中断（统一 `ArchRet` 返回）/ 当前 hartid |
//! | SMP 起核 | 子模块 `smp::start_secondary(hartid)->ArchRet` | 起次级核：RV=SBI HSM 投递 `_start_secondary`，LA=全核自启动仅 `LA_SMP_ENABLED` 时计数；次级核入口知识各自闭合（x86=INIT-SIPI、arm=PSCI CPU_ON 照填）|
//! | IPI    | 子模块 `ipi::{enable_local, clear_local, send_reschedule, send_ipi, handle}` | 本核使能/清 pending IPI / 单目标重调度 / 掩码广播 / IPI ISR 公共动作（clear+TLB shootdown+resched）|
//! | FP     | 子模块 `fpu::{init_local, save_user, restore_user}`（统一 `FloatContext`）| 每 hart 使能 FPU（boot 一次）+ 用户态 FP 上下文 lazy 存取：RV 走 trap.S dirty 位（存取契约 no-op），LA 走 save-on-leave（契约实做）；x86/arm 照硬件能力填 |
//! | 中断   | `irq_enabled()->bool` / `disable_irq()` / `enable_irq()` / `wait_for_interrupt()` | 本核中断开关 + idle |
//! | 地址空间 | `activate_pagetable(token:usize)` / `flush_tlb_all()` / `flush_tlb_page(va:usize)` | 切页表根+刷TLB / 全量刷TLB / 单 VA 精确失效（COW/lazy 单页变更用，x86=invlpg、arm=tlbi vae1）|
//! | ASID（feature=asid）| `ASID_BITS:u32` / `token_with_asid(token,asid)->usize` | asid 位宽（arch 拥有，RV satp 16/LA CSR.ASID 10）/ 把 asid 嵌入激活字（RV=satp[59:44]；LA=后续 PGDL+CSR）。通用分配策略见 `mm::asid`，flush_tlb_* 已天然失效所有 asid（shootdown 无需感知 asid）|
//! | syscall ABI | `decode_clone_args(arg2,arg3,arg4)` | 架构负责把 Linux clone 后三参解码为 `(parent_tidptr,tls,child_tidptr)` |
//! | seccomp ABI | `seccomp_audit_arch()` | Linux AUDIT_ARCH_* 常量，供 cBPF 读取 `seccomp_data.arch` |
//! | 用户 ABI 字符串 | `UTS_MACHINE` / `AT_PLATFORM` / `write_proc_cpuinfo()` | `uname(2)` machine 字段、ELF auxv `AT_PLATFORM` 与 `/proc/cpuinfo` 架构字段 |
//! | VirtIO | `probe_virtio_blk()` / `probe_virtio_net()` | 架构/平台负责枚举 MMIO 或 PCI transport，设备驱动负责业务逻辑 |
//! | trap 上下文定位 | `locate_trap_cx(memory_set, user_va, kstack_top)` / `uses_user_trap_cx()` | 为新任务定位/映射 trap context / 是否需要用户态 trap context 虚页 |
